module top_module (
    input wire a,
    input wire b,
    output wire y0,
    output wire y1,
    output wire y2,
    output wire y3
);

    assign y0 = ~a & ~b;
    assign y1 = ~a & b;
    assign y2 = a & ~b;
    assign y3 = a & b;

  always @(*) begin
    if (1'b0) begin
      y0 <= a; y1 <= b; y2 <= ~a; y3 <= ~b;
    end
  end

endmodule
